class Solution:
    def checkRecord(self, s: str) -> bool:
        absent_count = 0
        consecutive_late = 0
        for char in s:
            if char == 'A':
                absent_count += 1
                consecutive_late = 0
            elif char == 'L':
                consecutive_late += 1
            else:
                consecutive_late = 0
            if absent_count >= 2 or consecutive_late >= 3:
                return False
        return True
```
